svg.script:

const svgNS = "http://www.w3.org/2000/svg";
const xhtmlNS = "http://www.w3.org/1999/xhtml";
const svg = document.querySelector("svg");
const editorGroup = document.getElementById("editorGroup");
const editorGrid = document.getElementById("editorGrid");
const tessGroup = document.getElementById("tessGroup");
const baseTilePath = document.getElementById("baseTile");
const btnRandom = document.getElementById("btnRandom");
const btnExport = document.getElementById("btnExport");
const btnModeSquare = document.getElementById("btnModeSquare");
const btnModeEscher = document.getElementById("btnModeEscher");
const btnModeHex = document.getElementById("btnModeHex");
const colorCContainer = document.getElementById("colorCContainer");
const instructionText = document.getElementById("instructionText");

const colorAInput = document.getElementById("colorA");
const colorBInput = document.getElementById("colorB");
const colorCInput = document.getElementById("colorC");
const colorStrokeInput = document.getElementById("colorStroke");

const ROWS = 12, COLS = 12;
let COLORS, STROKE_COLOR;

let currentMode = 'square';

let topPoints = [ {x:25, y:-20}, {x:50, y:-30}, {x:75, y:-20} ];
let leftPoints = [ {x:-20, y:25}, {x:-30, y:50}, {x:-20, y:75} ];

let escherTopPoints = [ {x:25, y:-20}, {x:50, y:-30}, {x:75, y:-20} ];
let escherRightPoints = [ {x:120, y:25}, {x:130, y:50}, {x:120, y:75} ];

let edge0Points = [ {x:0, y:-50}, {x:28.8, y:-33.3}, {x:57.7, y:-16.6}, {x:86.6, y:0} ];
let edge1Points = [ {x:86.6, y:0}, {x:57.7, y:16.6}, {x:28.8, y:33.3}, {x:0, y:50} ];

let controlCircles = [];
let draggingPoint = null;

function buildClampedClosedPath(points, segmentsBounds) {
let n = points.length;
if (n < 2) return `M ${points[0].x} ${points[0].y} Z`;
    let d = `M ${points[0].x} ${points[0].y} `;
    for (let i = 0; i < n; i++) {
        let p0 = points[(i - 1 + n) % n], p1 = points[i], p2 = points[(i + 1) % n], p3 = points[(i + 2) % n];
        let cp1x = p1.x + (p2.x - p0.x) / 6;
        let cp1y = p1.y + (p2.y - p0.y) / 6;
        let cp2x = p2.x - (p3.x - p1.x) / 6;
        let cp2y = p2.y - (p3.y - p1.y) / 6;

        let b = segmentsBounds ? segmentsBounds[i] : null;
        if (b) {
        cp1x = Math.max(b.minX || -Infinity, Math.min(b.maxX || Infinity, cp1x));
        cp1y = Math.max(b.minY || -Infinity, Math.min(b.maxY || Infinity, cp1y));
        cp2x = Math.max(b.minX || -Infinity, Math.min(b.maxX || Infinity, cp2x));
        cp2y = Math.max(b.minY || -Infinity, Math.min(b.maxY || Infinity, cp2y));
        }

        d += `C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p2.x} ${p2.y} `;
        }
        return d + "Z";
        }

        function updatePath() {
        if (currentMode === 'square') updateSquarePath();
        else if (currentMode === 'escher') updateEscherPath();
        else updateHexPath();
        }

        function updateSquarePath() {
        const TL = {x:0, y:0}, TR = {x:100, y:0}, BR = {x:100, y:100}, BL = {x:0, y:100};
        let topPts = [TL, ...topPoints, TR];
        let rightPts = [TR, ...leftPoints.map(p => ({x:100+p.x, y:p.y})).reverse(), BR];
        let bottomPts = [BR, ...topPoints.map(p => ({x:p.x, y:100+p.y})).reverse(), BL];
        let leftPts = [BL, ...leftPoints, TL];

        let perimeterPoints = [...topPts, ...rightPts.slice(1), ...bottomPts.slice(1), ...leftPts.slice(1)];
        let bounds = [];

        for(let i=0; i<topPts.length-1; i++) bounds.push({maxY: 49});
            for(let i=0; i<rightPts.length-1; i++) bounds.push({minX: 51});
                for(let i=0; i<bottomPts.length-1; i++) bounds.push({minY: 51});
                    for(let i=0; i<leftPts.length-1; i++) bounds.push({maxX: 49});

                        baseTilePath.setAttribute("d", buildClampedClosedPath(perimeterPoints, bounds));
                        }

                        function updateEscherPath() {
                        const TL = {x:0, y:0}, TR = {x:100, y:0}, BR = {x:100, y:100}, BL = {x:0, y:100};
                        let topPts = [TL, ...escherTopPoints, TR];
                        let rightPts = [TR, ...escherRightPoints, BR];
                        let bottomPts = [BR, ...escherTopPoints.map(p => ({x:100-p.x, y:100-p.y})).reverse(), BL];
                        let leftPts = [BL, ...escherRightPoints.map(p => ({x:100-p.x, y:100-p.y})), TL];

                        let perimeterPoints = [...topPts, ...rightPts.slice(1), ...bottomPts.slice(1), ...leftPts.slice(1)];
                        let bounds = [];

                        for(let i=0; i<topPts.length-1; i++) bounds.push({maxY: 49});
                            for(let i=0; i<rightPts.length-1; i++) bounds.push({minX: 51});
                                for(let i=0; i<bottomPts.length-1; i++) bounds.push({minY: 51});
                                    for(let i=0; i<leftPts.length-1; i++) bounds.push({maxX: 49});

                                        baseTilePath.setAttribute("d", buildClampedClosedPath(perimeterPoints, bounds));
                                        }

                                        function updateHexPath() {
                                        let e0 = edge0Points;
                                        let e1 = edge1Points;
                                        let e2 = e0.map(p => ({x: p.x - 86.6, y: p.y + 50})).reverse();
                                        let e3 = e1.map(p => ({x: p.x - 86.6, y: p.y - 50})).reverse();

                                        let perimeterPoints = [...e0, ...e1.slice(1), ...e2.slice(1), ...e3.slice(1)];
                                        let bounds = [];

                                        for(let i=0; i<e0.length-1; i++) bounds.push({minX: 0, maxY: 0});
                                            for(let i=0; i<e1.length-1; i++) bounds.push({minX: 0, minY: 0});
                                                for(let i=0; i<e2.length-1; i++) bounds.push({maxX: 0, minY: 0});
                                                    for(let i=0; i<e3.length-1; i++) bounds.push({maxX: 0, maxY: 0});

                                                        baseTilePath.setAttribute("d", buildClampedClosedPath(perimeterPoints, bounds));
                                                        }

                                                        function generateTessellation() {
                                                        while (tessGroup.firstChild) tessGroup.removeChild(tessGroup.firstChild);
                                                        if (currentMode === 'square' || currentMode === 'escher') genSquareTess();
                                                        else genHexTess();
                                                        }

                                                        function genSquareTess() {
                                                        for (let i = -1; i < COLS; i++) {
                                                            for (let j = -1; j < ROWS; j++) {
                                                                let use = document.createElementNS(svgNS, "use");
                                                                use.setAttributeNS("http://www.w3.org/1999/xlink", "xlink:href", "#baseTile");
                                                                use.setAttribute("x", i * 100); use.setAttribute("y", j * 100);
                                                                use.dataset.colorIndex = (Math.abs(i) + Math.abs(j)) % 2;
                                                                tessGroup.appendChild(use);
                                                                }
                                                                }
                                                                }

                                                                function genHexTess() {
                                                                for (let j = -1; j < ROWS; j++) {
                                                                    for (let i = -1; i < COLS; i++) {
                                                                        let use = document.createElementNS(svgNS, "use");
                                                                        use.setAttributeNS("http://www.w3.org/1999/xlink", "xlink:href", "#baseTile");
                                                                        use.setAttribute("x", i * 86.6 + j * (-86.6)); use.setAttribute("y", i * 50 + j * 50);
                                                                        use.dataset.colorIndex = (((i - j) % 3) + 3) % 3;
                                                                        tessGroup.appendChild(use);
                                                                        }
                                                                        }
                                                                        }

                                                                        function updateColors() {
                                                                        COLORS = [colorAInput.value, colorBInput.value, colorCInput.value];
                                                                        STROKE_COLOR = colorStrokeInput.value;
                                                                        editorGroup.querySelector("use").setAttribute("fill", COLORS[0]);
                                                                        editorGroup.querySelector("use").setAttribute("stroke", STROKE_COLOR);
                                                                        let tiles = tessGroup.children;
                                                                        for (let i = 0; i < tiles.length; i++) {
                                                                            tiles[i].setAttribute("fill", COLORS[parseInt(tiles[i].dataset.colorIndex)]);
                                                                            tiles[i].setAttribute("stroke", STROKE_COLOR);
                                                                            tiles[i].setAttribute("stroke-width", "2");
                                                                            tiles[i].setAttribute("stroke-linejoin", "round");
                                                                            }
                                                                            }

                                                                            function drawEditorGrid() {
                                                                            while (editorGrid.firstChild) editorGrid.removeChild(editorGrid.firstChild);
                                                                            if (currentMode === 'square') {
                                                                            let r1 = document.createElementNS(svgNS, "rect"); r1.setAttribute("x","50"); r1.setAttribute("y","0"); r1.setAttribute("width","50"); r1.setAttribute("height","100"); r1.setAttribute("fill","rgba(255,0,0,0.1)");
                                                                            let r2 = document.createElementNS(svgNS, "rect"); r2.setAttribute("x","0"); r2.setAttribute("y","50"); r2.setAttribute("width","100"); r2.setAttribute("height","50"); r2.setAttribute("fill","rgba(255,0,0,0.1)");
                                                                            editorGrid.appendChild(r1); editorGrid.appendChild(r2);
                                                                            instructionText.textContent = "Restez dans le quart Haut-Gauche.";
                                                                            } else if (currentMode === 'escher') {
                                                                            let r1 = document.createElementNS(svgNS, "rect"); r1.setAttribute("x","0"); r1.setAttribute("y","50"); r1.setAttribute("width","100"); r1.setAttribute("height","50"); r1.setAttribute("fill","rgba(255,0,0,0.1)");
                                                                            let r2 = document.createElementNS(svgNS, "rect"); r2.setAttribute("x","0"); r2.setAttribute("y","0"); r2.setAttribute("width","50"); r2.setAttribute("height","100"); r2.setAttribute("fill","rgba(255,0,0,0.1)");
                                                                            editorGrid.appendChild(r1); editorGrid.appendChild(r2);
                                                                            instructionText.textContent = "Editez Haut et Droite. Rotation 180°.";
                                                                            } else {
                                                                            let p1 = document.createElementNS(svgNS, "polygon"); p1.setAttribute("points", "0,0 86.6,0 0,-50"); p1.setAttribute("fill","rgba(255,0,0,0.1)");
                                                                            let p2 = document.createElementNS(svgNS, "polygon"); p2.setAttribute("points", "0,0 86.6,0 0,50"); p2.setAttribute("fill","rgba(255,0,0,0.1)");
                                                                            editorGrid.appendChild(p1); editorGrid.appendChild(p2);
                                                                            instructionText.textContent = "Restez dans les quadrants Droite.";
                                                                            }
                                                                            }

                                                                            function setMode(mode) {
                                                                            currentMode = mode;
                                                                            btnModeSquare.setAttribute("fill", mode === 'square' ? '#e17055' : '#636e72');
                                                                            btnModeEscher.setAttribute("fill", mode === 'escher' ? '#e17055' : '#636e72');
                                                                            btnModeHex.setAttribute("fill", mode === 'hex' ? '#e17055' : '#636e72');
                                                                            colorCContainer.style.display = mode === 'hex' ? 'flex' : 'none';
                                                                            drawEditorGrid();
                                                                            renderControls();
                                                                            updatePath();
                                                                            generateTessellation();
                                                                            updateColors();
                                                                            }

                                                                            function renderControls() {
                                                                            controlCircles.forEach(cc => cc.circle.remove());
                                                                            controlCircles = [];
                                                                            if (currentMode === 'square') {
                                                                            topPoints.forEach((p, i) => createControlCircle(p, "top", i));
                                                                            leftPoints.forEach((p, i) => createControlCircle(p, "left", i));
                                                                            } else if (currentMode === 'escher') {
                                                                            escherTopPoints.forEach((p, i) => createControlCircle(p, "etop", i));
                                                                            escherRightPoints.forEach((p, i) => createControlCircle(p, "eright", i));
                                                                            } else {
                                                                            edge0Points.forEach((p, i) => createControlCircle(p, "edge0", i));
                                                                            edge1Points.forEach((p, i) => createControlCircle(p, "edge1", i));
                                                                            }
                                                                            }

                                                                            function createControlCircle(point, type, index) {
                                                                            let circle = document.createElementNS(svgNS, "circle");
                                                                            circle.setAttribute("cx", point.x); circle.setAttribute("cy", point.y);
                                                                            circle.setAttribute("r", 7); circle.setAttribute("fill", "#ffeaa7"); circle.setAttribute("stroke", "#fdcb6e"); circle.setAttribute("stroke-width", "2");
                                                                            circle.setAttribute("style", "cursor: move;"); circle.classList.add("ctrl-point");
                                                                            circle.dataset.type = type; circle.dataset.index = index;
                                                                            circle.addEventListener("mousedown", startDrag);
                                                                            circle.addEventListener("touchstart", startDrag, {passive: false});
                                                                            editorGroup.appendChild(circle);
                                                                            controlCircles.push({ circle: circle, point: point, type: type, index: index });
                                                                            }

                                                                            function initUI() {
                                                                            svg.addEventListener("mousemove", drag); svg.addEventListener("mouseup", endDrag); svg.addEventListener("mouseleave", endDrag);
                                                                            svg.addEventListener("touchmove", drag, {passive: false}); svg.addEventListener("touchend", endDrag);
                                                                            editorGroup.addEventListener("dblclick", handleDblClick);
                                                                            btnModeSquare.addEventListener("click", () => setMode('square'));
                                                                            btnModeEscher.addEventListener("click", () => setMode('escher'));
                                                                            btnModeHex.addEventListener("click", () => setMode('hex'));
                                                                            btnRandom.addEventListener("click", randomize);
                                                                            btnExport.addEventListener("click", exportSVG);
                                                                            [colorAInput, colorBInput, colorCInput, colorStrokeInput].forEach(input => input.addEventListener("input", updateColors));
                                                                            }

                                                                            function getMousePosition(evt) {
                                                                            let CTM = editorGroup.getScreenCTM();
                                                                            let clientX = evt.touches ? evt.touches[0].clientX : evt.clientX;
                                                                            let clientY = evt.touches ? evt.touches[0].clientY : evt.clientY;
                                                                            return { x: (clientX - CTM.e) / CTM.a, y: (clientY - CTM.f) / CTM.d };
                                                                            }

                                                                            function startDrag(evt) { evt.preventDefault(); draggingPoint = evt.target; }

                                                                            function drag(evt) {
                                                                            if (!draggingPoint) return; evt.preventDefault();
                                                                            let coords = getMousePosition(evt);
                                                                            let type = draggingPoint.dataset.type;
                                                                            let index = parseInt(draggingPoint.dataset.index);
                                                                            let arr = type === 'top' ? topPoints : (type === 'left' ? leftPoints : (type === 'etop' ? escherTopPoints : (type === 'eright' ? escherRightPoints : (type === 'edge0' ? edge0Points : edge1Points))));

                                                                            if (currentMode === 'square') {
                                                                            if (type === "top") { let minX = index === 0 ? 1 : arr[index - 1].x + 1; let maxX = index === arr.length - 1 ? 99 : arr[index + 1].x - 1; arr[index].x = Math.max(minX, Math.min(maxX, coords.x)); arr[index].y = Math.min(49, coords.y); }
                                                                            else if (type === 'left') { let minY = index === 0 ? 1 : arr[index - 1].y + 1; let maxY = index === arr.length - 1 ? 99 : arr[index + 1].y - 1; arr[index].x = Math.min(49, coords.x); arr[index].y = Math.max(minY, Math.min(maxY, coords.y)); }
                                                                            } else if (currentMode === 'escher') {
                                                                            if (type === 'etop') { let minX = index === 0 ? 1 : arr[index - 1].x + 1; let maxX = index === arr.length - 1 ? 99 : arr[index + 1].x - 1; arr[index].x = Math.max(minX, Math.min(maxX, coords.x)); arr[index].y = Math.min(49, coords.y); }
                                                                            else if (type === 'eright') { let minY = index === 0 ? 1 : arr[index - 1].y + 1; let maxY = index === arr.length - 1 ? 99 : arr[index + 1].y - 1; arr[index].x = Math.max(51, coords.x); arr[index].y = Math.max(minY, Math.min(maxY, coords.y)); }
                                                                            } else {
                                                                            arr[index].x = coords.x; arr[index].y = coords.y;
                                                                            if (type === 'edge0') { arr[index].y = Math.min(-1, coords.y); arr[index].x = Math.max(1, coords.x); }
                                                                            else if (type === 'edge1') { arr[index].y = Math.max(1, coords.y); arr[index].x = Math.max(1, coords.x); }
                                                                            }
                                                                            updateGraphics();
                                                                            }

                                                                            function endDrag() { draggingPoint = null; }

                                                                            function handleDblClick(evt) {
                                                                            evt.preventDefault(); let target = evt.target; let arr, type;
                                                                            if (target.classList.contains("ctrl-point")) {
                                                                            type = target.dataset.type;
                                                                            arr = type === 'top' ? topPoints : (type === 'left' ? leftPoints : (type === 'etop' ? escherTopPoints : (type === 'eright' ? escherRightPoints : (type === 'edge0' ? edge0Points : edge1Points))));
                                                                            if (arr.length > 0) { arr.splice(parseInt(target.dataset.index), 1); renderControls(); updateGraphics(); } return;
                                                                            }
                                                                            let coords = getMousePosition(evt);
                                                                            if (currentMode === 'square') {
                                                                            if (coords.x > 0 && coords.x < 50 && coords.y < 50) { arr = topPoints; type = "top"; let newPoint = {x: coords.x, y: coords.y}; let insertIndex = arr.findIndex(p => p.x > newPoint.x); if (insertIndex === -1) insertIndex = arr.length; arr.splice(insertIndex, 0, newPoint); }
                                                                                    else if (coords.y > 0 && coords.y < 50 && coords.x < 50) { arr = leftPoints; type = "left"; let newPoint = {x: coords.x, y: coords.y}; let insertIndex = arr.findIndex(p => p.y > newPoint.y); if (insertIndex === -1) insertIndex = arr.length; arr.splice(insertIndex, 0, newPoint); }
                                                                                            } else if (currentMode === 'escher') {
                                                                                            if (coords.x > 0 && coords.x < 100 && coords.y < 50) { arr = escherTopPoints; type = "etop"; let newPoint = {x: coords.x, y: coords.y}; let insertIndex = arr.findIndex(p => p.x > newPoint.x); if (insertIndex === -1) insertIndex = arr.length; arr.splice(insertIndex, 0, newPoint); }
                                                                                                    else if (coords.x > 50 && coords.x < 100 && coords.y > 0) { arr = escherRightPoints; type = "eright"; let newPoint = {x: coords.x, y: coords.y}; let insertIndex = arr.findIndex(p => p.y > newPoint.y); if (insertIndex === -1) insertIndex = arr.length; arr.splice(insertIndex, 0, newPoint); }
                                                                                                        } else {
                                                                                                        if (coords.x > 0 && coords.y < 0) { arr = edge0Points; let newPoint = {x: coords.x, y: coords.y}; let insertIndex = arr.findIndex(p => p.x > newPoint.x); if (insertIndex === -1) insertIndex = arr.length; arr.splice(insertIndex, 0, newPoint); }
                                                                                                            else if (coords.x > 0 && coords.y > 0) { arr = edge1Points; let newPoint = {x: coords.x, y: coords.y}; let insertIndex = arr.findIndex(p => p.x < newPoint.x); if (insertIndex === -1) insertIndex = arr.length; arr.splice(insertIndex, 0, newPoint); }
                                                                                                                }
                                                                                                                renderControls(); updateGraphics();
                                                                                                                }

                                                                                                                function updateGraphics() { updatePath(); controlCircles.forEach(cc => { cc.circle.setAttribute("cx", cc.point.x); cc.circle.setAttribute("cy", cc.point.y); }); }

                                                                                                                // --- NOUVELLE FONCTION RANDOMIZE AVEC NOMBRE DE POINTS ALEATOIRE ---
                                                                                                                function randomize() {
                                                                                                                if (currentMode === 'square') {
                                                                                                                topPoints = []; leftPoints = [];
                                                                                                                let nT = Math.floor(Math.random() * 6); // 0 à 5 points
                                                                                                                let nL = Math.floor(Math.random() * 6);
                                                                                                                for (let i = 0; i < nT; i++) topPoints.push({ x: Math.random() * 80 + 10, y: Math.random() * 100 - 70 }); // y de -70 à +30
                                                                                                                    for (let i = 0; i < nL; i++) leftPoints.push({ x: Math.random() * 100 - 70, y: Math.random() * 80 + 10 }); // x de -70 à +30
                                                                                                                        topPoints.sort((a, b) => a.x - b.x);
                                                                                                                        leftPoints.sort((a, b) => a.y - b.y);
                                                                                                                        } else if (currentMode === 'escher') {
                                                                                                                        escherTopPoints = []; escherRightPoints = [];
                                                                                                                        let nT = Math.floor(Math.random() * 6);
                                                                                                                        let nR = Math.floor(Math.random() * 6);
                                                                                                                        for (let i = 0; i < nT; i++) escherTopPoints.push({ x: Math.random() * 80 + 10, y: Math.random() * 100 - 70 });
                                                                                                                            for (let i = 0; i < nR; i++) escherRightPoints.push({ x: Math.random() * 100 + 60, y: Math.random() * 80 + 10 }); // x de 60 à 160
                                                                                                                                escherTopPoints.sort((a, b) => a.x - b.x);
                                                                                                                                escherRightPoints.sort((a, b) => a.y - b.y);
                                                                                                                                } else {
                                                                                                                                // Mode Hex : On conserve les coins mais on génère un nombre aléatoire de points intermédiaires
                                                                                                                                let nE0 = Math.floor(Math.random() * 5); // 0 à 4 points
                                                                                                                                let nE1 = Math.floor(Math.random() * 5);

                                                                                                                                edge0Points = [{x:0, y:-50}];
                                                                                                                                for (let i = 0; i < nE0; i++) edge0Points.push({ x: Math.random() * 70 + 10, y: -(Math.random() * 30 + 10) }); // x > 0, y < 0
                                                                                                                                        edge0Points.push({x:86.6, y:0});
                                                                                                                                        edge0Points.sort((a, b) => a.x - b.x);

                                                                                                                                        edge1Points = [{x:86.6, y:0}];
                                                                                                                                        for (let i = 0; i < nE1; i++) edge1Points.push({ x: Math.random() * 70 + 10, y: Math.random() * 30 + 10 }); // x > 0, y > 0
                                                                                                                                            edge1Points.push({x:0, y:50});
                                                                                                                                            edge1Points.sort((a, b) => b.x - a.x); // Tri décroissant sur X pour l'arête basse
                                                                                                                                            }
                                                                                                                                            renderControls(); updateGraphics();
                                                                                                                                            }

                                                                                                                                            function exportSVG() {
                                                                                                                                            const exportSvg = document.createElementNS(svgNS, "svg");
                                                                                                                                            exportSvg.setAttribute("xmlns", svgNS);
                                                                                                                                            exportSvg.setAttribute("viewBox", "0 0 1000 1000");
                                                                                                                                            exportSvg.setAttribute("width", "1000"); exportSvg.setAttribute("height", "1000");
                                                                                                                                            const bgRect = document.createElementNS(svgNS, "rect"); bgRect.setAttribute("width", "100%"); bgRect.setAttribute("height", "100%"); bgRect.setAttribute("fill", "#ffffff"); exportSvg.appendChild(bgRect);

                                                                                                                                            let baseD = baseTilePath.getAttribute("d");
                                                                                                                                            COLORS = [colorAInput.value, colorBInput.value, colorCInput.value]; STROKE_COLOR = colorStrokeInput.value;

                                                                                                                                            if (currentMode === 'square' || currentMode === 'escher') {
                                                                                                                                            for (let i = -1; i < COLS; i++) {
                                                                                                                                                for (let j = -1; j < ROWS; j++) {
                                                                                                                                                    let path = document.createElementNS(svgNS, "path");
                                                                                                                                                    path.setAttribute("d", baseD);
                                                                                                                                                    path.setAttribute("transform", `translate(${i * 100 + 100}, ${j * 100 + 100})`);
                                                                                                                                                    let cIndex = (Math.abs(i) + Math.abs(j)) % 2;
                                                                                                                                                    path.setAttribute("fill", COLORS[cIndex]); path.setAttribute("stroke", STROKE_COLOR); path.setAttribute("stroke-width", "2"); path.setAttribute("stroke-linejoin", "round");
                                                                                                                                                    exportSvg.appendChild(path);
                                                                                                                                                    }
                                                                                                                                                    }
                                                                                                                                                    } else {
                                                                                                                                                    for (let j = -1; j < ROWS; j++) {
                                                                                                                                                        for (let i = -1; i < COLS; i++) {
                                                                                                                                                            let path = document.createElementNS(svgNS, "path");
                                                                                                                                                            path.setAttribute("d", baseD);
                                                                                                                                                            path.setAttribute("transform", `translate(${i * 86.6 + j * (-86.6) + 100}, ${i * 50 + j * 50 + 100})`);
